/**
 * Send a notification through the appropriate adapter.
 * Queues per-recipient to guarantee FIFO delivery order.
 * Falls back to in-memory storage if no adapter is registered for the channel.
 */
private sendNotification(payload: NotificationPayload): Promise<void> {
  const recipient = payload.recipient;
  const previous = this.recipientQueues.get(recipient) ?? Promise.resolve();
  const current = previous.then(() => this.deliverNotification(payload));
  this.recipientQueues.set(recipient, current.catch(() => {}));
  return current;
}

/**
 * Internal delivery — called in sequence per recipient via the queue.
 */
private async deliverNotification(payload: NotificationPayload): Promise<void> {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    channel: payload.channel,
    type: payload.type,
    priority: payload.priority,
    status: 'pending',
    metadata: payload.metadata,
    sentAt: new Date(),
  };

  const adapter = this.adapters.get(payload.channel);
  if (adapter) {
    const result = await adapter.send(payload);
    notification.status = result.success ? 'sent' : 'failed';

    if (result.success) {
      await this.eventBus.emit({
        type: 'notification:sent',
        notification,
        channel: payload.channel,
        timestamp: new Date(),
      });
    } else {
      await this.eventBus.emit({
        type: 'notification:failed',
        recipient: payload.recipient,
        subject: payload.subject,
        channel: payload.channel,
        error: result.error ?? 'Unknown error',
        timestamp: new Date(),
      });
    }
  } else {
    // No adapter registered — store as sent (in-memory fallback)
    notification.status = 'sent';
  }

  this.notifications.push(notification);
  this.logger.info(`Notification ${notification.id} [${notification.status}] to ${payload.recipient}`);
}

