import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationAdapter, NotificationResult } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

it('should deliver notifications in order when events fire concurrently', async () => {
  // Create a slow adapter that delays delivery to expose ordering issues
  const deliveryOrder: string[] = [];
  let resolveFirst: (() => void) | undefined;
  const firstSendStarted = new Promise<void>((r) => { resolveFirst = r; });
  let callCount = 0;

  const slowAdapter: NotificationAdapter = {
    channel: 'email' as const,
    async send(payload: NotificationPayload): Promise<NotificationResult> {
      callCount++;
      if (callCount === 1) {
        // First notification: signal that it started, then wait
        resolveFirst!();
        await new Promise<void>((resolve) => setTimeout(resolve, 50));
      }
      deliveryOrder.push(payload.subject);
      return { success: true };
    },
  };

  service.registerAdapter(slowAdapter);

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'alice@example.com',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // Fire both events concurrently — the first one is slow
  const p1 = eventBus.emit(orderCreatedEvent);
  // Wait for the first send to start so we know it's in-flight
  await firstSendStarted;
  const p2 = eventBus.emit(statusChangedEvent);

  await Promise.all([p1, p2]);

  // Despite the first notification being slower, it should still be delivered first
  expect(deliveryOrder[0]).toContain('Order Confirmation');
  expect(deliveryOrder[1]).toContain('Order Update');

  // Verify both notifications were stored in order
  const notifications = service.getNotifications();
  expect(notifications).toHaveLength(2);
  expect(notifications[0]?.subject).toContain('Order Confirmation');
  expect(notifications[1]?.subject).toContain('Order Update');
});

